function identity<T>(arg: T): T {
  return arg;
}

const num = identity<number>(42); // num is number
const str = identity<string>('hello'); // str is string

// Generic with arrays
type Box<T> = {
  contents: T[];
};

const numberBox: Box<number> = { contents: [1, 2, 3] };
const stringBox: Box<string> = { contents: ['a', 'b', 'c'] };

